(() => {
  if (window.__BARBA_GSAP_SCOPED_INITIALIZED__) return;
  window.__BARBA_GSAP_SCOPED_INITIALIZED__ = true;

  const state = {
    lenis: null,
    cleanups: [],
    onceReady: false,
    reducedMotion: false,
    rmMQ: window.matchMedia("(prefers-reduced-motion: reduce)"),
    resizeHandler: null
  };

  history.scrollRestoration = "manual";
  state.reducedMotion = state.rmMQ.matches;

  const onReducedMotionChange = (e) => { state.reducedMotion = e.matches; };
  state.rmMQ.addEventListener?.("change", onReducedMotionChange);
  state.rmMQ.addListener?.(onReducedMotionChange);

  const qsa = (scope, selector) => Array.from((scope || document).querySelectorAll(selector));

  const addCleanup = (fn) => {
    if (typeof fn === "function") state.cleanups.push(fn);
  };

  const runCleanups = () => {
    state.cleanups.forEach((fn) => {
      try { fn(); } catch (_) {}
    });
    state.cleanups.length = 0;
  };

  const themeConfig = {
    light: { nav: "dark", transition: "light" },
    dark: { nav: "light", transition: "dark" }
  };

  function registerPlugins() {
    if (!window.gsap) return;
    const plugins = [
      window.CustomEase,
      window.ScrollTrigger,
      window.SplitText,
      window.Draggable,
      window.InertiaPlugin,
      window.Observer
    ].filter(Boolean);

    if (plugins.length) gsap.registerPlugin(...plugins);

    if (window.CustomEase) {
      CustomEase.create("osmo", "0.625, 0.05, 0, 1");
      CustomEase.create("parallax", "0.7, 0.05, 0.13, 1");
      gsap.defaults({ ease: "osmo", duration: 0.6 });
    }
  }

  function initLenis() {
    if (!window.gsap || !window.Lenis || state.lenis) return;

    state.lenis = new Lenis({
      lerp: 0.165,
      wheelMultiplier: 1.25
    });

    if (window.ScrollTrigger) {
      state.lenis.on("scroll", ScrollTrigger.update);
    }

    gsap.ticker.add((time) => {
      state.lenis?.raf(time * 1000);
    });

    gsap.ticker.lagSmoothing(0);
  }

  function stopLenis() {
    try { state.lenis?.stop?.(); } catch (_) {}
  }

  function startLenis() {
    try {
      state.lenis?.resize?.();
      state.lenis?.start?.();
    } catch (_) {}
  }

  function refreshScroll() {
    if (window.ScrollTrigger) ScrollTrigger.refresh(true);
  }

  function refreshScrollHard() {
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        refreshScroll();
        setTimeout(() => refreshScroll(), 120);
      });
    });
  }
function normalizePath(path) {
  const clean = path.replace(/\/+$/, "");
  return clean || "/";
}

function syncWebflowCurrentNav(url) {
  const currentPath = normalizePath(new URL(url || window.location.href, window.location.origin).pathname);

  document.querySelectorAll("nav a[href]").forEach((link) => {
    const raw = link.getAttribute("href");
    if (!raw || raw.startsWith("#") || raw.startsWith("mailto:") || raw.startsWith("tel:")) return;

    const linkPath = normalizePath(new URL(link.href, window.location.origin).pathname);
    const isCurrent = linkPath === currentPath;

    link.classList.toggle("w--current", isCurrent);
    if (isCurrent) link.setAttribute("aria-current", "page");
    else link.removeAttribute("aria-current");
  });
}

  // once on first load
syncWebflowCurrentNav(window.location.href);

// after each Barba nav
barba.hooks.after((data) => {
  syncWebflowCurrentNav(data.next?.url?.href || window.location.href);
});


  function applyThemeFrom(container) {
    const pageTheme = container?.dataset?.pageTheme || "light";
    const config = themeConfig[pageTheme] || themeConfig.light;

    document.body.dataset.pageTheme = pageTheme;

    const transitionEl = document.querySelector("[data-theme-transition]");
    if (transitionEl) transitionEl.dataset.themeTransition = config.transition;

    const nav = document.querySelector("[data-theme-nav]");
    if (nav) nav.dataset.themeNav = config.nav;
  }

  function resetPage(container) {
    window.scrollTo(0, 0);

    if (window.gsap && container) {
      gsap.set(container, { clearProps: "position,top,left,right,zIndex,transform,opacity,visibility" });
    }

    startLenis();
    refreshScroll();
  }

  function initBarbaNavUpdate(data) {
    if (!data?.next?.html) return;

    const tpl = document.createElement("template");
    tpl.innerHTML = data.next.html.trim();

    const nextNodes = tpl.content.querySelectorAll("[data-barba-update]");
    const currentNodes = document.querySelectorAll("nav [data-barba-update]");

    currentNodes.forEach((curr, index) => {
      const next = nextNodes[index];
      if (!next) return;

      const newStatus = next.getAttribute("aria-current");
      if (newStatus !== null) curr.setAttribute("aria-current", newStatus);
      else curr.removeAttribute("aria-current");

      curr.setAttribute("class", next.getAttribute("class") || "");
    });
  }

  (function forceReloadOnLocaleSwitch() {
  // Put this near the top of your main script, before barba.init()
  document.addEventListener("click", (e) => {
    const link = e.target.closest('[data-locale-switch] a[href], a[data-locale-switch][href]');
    if (!link) return;

    // Let normal navigation happen (full page load) – block Barba
    e.preventDefault();
    e.stopPropagation();

    // Hard navigate
    window.location.href = link.href;
  }, true); // capture = true so it runs before Barba intercepts
})();

  function runPageOnceAnimation(next) {
    const tl = gsap.timeline();
    tl.call(() => resetPage(next), null, 0);
    return tl;
  }

  function runPageLeaveAnimation(current) {
    const tl = gsap.timeline({
      onComplete: () => current?.remove?.()
    });

    if (state.reducedMotion) return tl.set(current, { autoAlpha: 0 });

    const transitionWrap = document.querySelector("[data-transition-wrap]");
    const transitionDark = transitionWrap?.querySelector("[data-transition-dark]");

    if (transitionWrap && transitionDark) {
      tl.set(transitionWrap, { zIndex: 2 }, 0);
      tl.fromTo(
        transitionDark,
        { autoAlpha: 0 },
        { autoAlpha: 1, duration: 1.2, ease: "parallax" },
        0
      );
      tl.fromTo(
        current,
        { y: "0vh" },
        { y: "-25vh", duration: 1.2, ease: "parallax" },
        0
      );
      tl.set(transitionDark, { autoAlpha: 0 });
    } else {
      tl.to(current, { autoAlpha: 0, duration: 0.4 });
    }

    return tl;
  }

  function runPageEnterAnimation(next) {
    const tl = gsap.timeline();

    if (state.reducedMotion) {
      tl.set(next, { autoAlpha: 1 });
      tl.add("pageReady");
      tl.call(resetPage, [next], "pageReady");
      return new Promise((resolve) => tl.call(resolve, null, "pageReady"));
    }

    tl.add("startEnter", 0);
    tl.set(next, { zIndex: 3 }, "startEnter");
    tl.fromTo(
      next,
      { y: "100vh", autoAlpha: 1 },
      { y: "0vh", duration: 1.2, ease: "parallax", clearProps: "transform,zIndex" },
      "startEnter"
    );

    tl.add("pageReady");
    tl.call(resetPage, [next], "pageReady");

    return new Promise((resolve) => tl.call(resolve, null, "pageReady"));
  }

  function initHeadingVisibility(scope) {
    qsa(scope, '[data-split="heading"]').forEach((el) => {
      el.style.visibility = "visible";
    });
  }

  
function primeWipes(scope) {
  if (!window.gsap) return;

  qsa(scope, "[data-wipe-reveal]").forEach((el) => {
    const style = getComputedStyle(el);
    if (style.position === "static") el.style.position = "relative";
    if (style.overflow === "visible") el.style.overflow = "hidden";

    let overlay = el.querySelector(":scope > .wipe_overlay");
    if (!overlay) {
      overlay = document.createElement("div");
      overlay.className = "wipe_overlay";
      overlay.style.position = "absolute";
      overlay.style.inset = "0";
      overlay.style.zIndex = "2";
      overlay.style.pointerEvents = "none";
      el.appendChild(overlay);
    }

    overlay.style.background = style.getPropertyValue("--wipe-color").trim() || "#000002";

    const { from } = wipeVars(el.getAttribute("data-wipe-reveal"));
    gsap.set(overlay, from); // covered state
    el._wipePlayed = false;
    el.setAttribute("data-wipe-ready", "true");
  });
}
barba.hooks.beforeEnter((data) => {
  gsap.set(data.next.container, { position: "fixed", top: 0, left: 0, right: 0 });
  stopLenis();
  applyThemeFrom(data.next.container);
  primeWipes(data.next.container); // <- add this
});

  
  function wipeVars(direction) {
    switch ((direction || "left").toLowerCase()) {
      case "right":
        return { from: { xPercent: 0 }, to: { xPercent: 100 } };
      case "top":
        return { from: { yPercent: 0 }, to: { yPercent: -100 } };
      case "bottom":
        return { from: { yPercent: 0 }, to: { yPercent: 100 } };
      default:
        return { from: { xPercent: 0 }, to: { xPercent: -100 } };
    }
  }

  function initWipes(scope) {
    if (!window.gsap || !window.ScrollTrigger) return;

    const createdOverlays = [];
    const triggers = [];
    const tweens = [];

    qsa(scope, "[data-wipe-reveal]").forEach((el) => {
      const style = getComputedStyle(el);
      if (style.position === "static") el.style.position = "relative";
      if (style.overflow === "visible") el.style.overflow = "hidden";

      let overlay = el.querySelector(":scope > .wipe_overlay");
      const isNew = !overlay;

      if (!overlay) {
        overlay = document.createElement("div");
        overlay.className = "wipe_overlay";
        overlay.style.position = "absolute";
        overlay.style.inset = "0";
        overlay.style.zIndex = "2";
        overlay.style.pointerEvents = "none";
        overlay.style.background = style.getPropertyValue("--wipe-color").trim() || "#000002";
        el.appendChild(overlay);
      }

      if (isNew) createdOverlays.push(overlay);

      const { from, to } = wipeVars(el.getAttribute("data-wipe-reveal"));
      gsap.set(overlay, from);
      el._wipePlayed = false;

      const play = () => {
        if (el._wipePlayed) return;
        el._wipePlayed = true;
        tweens.push(gsap.to(overlay, { ...to, duration: 1.1, ease: "power2.out", overwrite: "auto" }));
      };

      const st = ScrollTrigger.create({
        trigger: el,
        start: "top 80%",
        once: true,
        onEnter: play,
        onRefresh: (self) => {
          if (!el._wipePlayed && self.isActive) play();
        }
      });

      triggers.push(st);
    });

    addCleanup(() => {
      tweens.forEach((t) => t.kill());
      triggers.forEach((st) => st.kill(true));
      createdOverlays.forEach((ov) => ov.remove());
    });
  }

  function initImageStair(scope) {
    if (!window.gsap || !window.ScrollTrigger) return;

    const ctx = gsap.context(() => {
      qsa(scope, ".image_stair_wrapper").forEach((wrap) => {
        const items = qsa(wrap, ".stair_img_wrap");
        if (!items.length) return;

        gsap.to(items, {
          y: 0,
          ease: "none",
          overwrite: "auto",
          scrollTrigger: {
            trigger: wrap,
            start: "top 80%",
            end: "bottom 30%",
            scrub: true,
            invalidateOnRefresh: true
          }
        });
      });
    }, scope);

    addCleanup(() => ctx.revert());
  }

  function initHighlightText(scope) {
    if (!window.gsap || !window.ScrollTrigger || !window.SplitText) return;

    const splits = [];
    const ctx = gsap.context(() => {
      qsa(scope, "[data-highlight-text]").forEach((heading) => {
        const scrollStart = heading.getAttribute("data-highlight-scroll-start") || "top 90%";
        const scrollEnd = heading.getAttribute("data-highlight-scroll-end") || "center 40%";
        const fadedValue = Number(heading.getAttribute("data-highlight-fade") || 0.2);
        const staggerValue = Number(heading.getAttribute("data-highlight-stagger") || 0.1);

        const split = new SplitText(heading, { type: "words,chars" });
        splits.push(split);

        gsap.from(split.chars, {
          autoAlpha: fadedValue,
          stagger: staggerValue,
          ease: "linear",
          scrollTrigger: {
            trigger: heading,
            start: scrollStart,
            end: scrollEnd,
            scrub: true
          }
        });
      });
    }, scope);

    addCleanup(() => {
      ctx.revert();
      splits.forEach((split) => split.revert?.());
    });
  }

  function initHeadingSplit(scope) {
    if (!window.gsap || !window.ScrollTrigger || !window.SplitText) return;

    const splitInstances = [];
    const ctx = gsap.context(() => {
      qsa(scope, '[data-split="heading"]').forEach((heading) => {
        heading.style.visibility = "visible";

        const split = SplitText.create(heading, {
          type: "lines",
          autoSplit: true,
          mask: "lines",
          onSplit(instance) {
            return gsap.from(instance.lines, {
              duration: 1.35,
              yPercent: 110,
              stagger: 0.2,
              ease: "expo.out",
              scrollTrigger: {
                trigger: heading,
                start: "top 80%",
                once: true
              }
            });
          }
        });

        splitInstances.push(split);
      });
    }, scope);

    addCleanup(() => {
      ctx.revert();
      splitInstances.forEach((split) => split?.revert?.());
    });
  }

  function initFAQ(scope) {
    if (!window.gsap) return;

    const items = qsa(scope, ".faq_item");
    if (!items.length) return;

    const timelines = new Map();
    const listeners = [];

    items.forEach((item) => {
      const answer = item.querySelector(".answer_wrapper");
      const trigger = item.querySelector(".question_wrapper") || item;
      const icon = item.querySelector(".plus_icon");
      if (!answer || !trigger) return;

      const computed = getComputedStyle(answer);
      const startsHidden = computed.display === "none";
      const openDisplay = startsHidden ? "flex" : computed.display;

      gsap.set(answer, {
        display: startsHidden ? "none" : openDisplay,
        height: 0,
        overflow: "hidden",
        opacity: 0,
        paddingTop: 0
      });
      if (icon) gsap.set(icon, { rotate: 0 });

      const tl = gsap.timeline({
        paused: true,
        onReverseComplete: () => {
          if (startsHidden) gsap.set(answer, { display: "none" });
        }
      });

      tl.set(answer, { display: openDisplay })
        .to(answer, { height: "auto", duration: 0.5, ease: "power2.out" }, 0)
        .to(answer, { opacity: 1, duration: 0.25, ease: "power1.out" }, 0.08)
        .to(answer, { paddingTop: 16, duration: 0.35, ease: "power2.out" }, 0.08);

      if (icon) tl.to(icon, { rotate: 45, duration: 0.35, ease: "power2.out" }, 0);

      tl.reverse(0);
      timelines.set(item, tl);

      const onClick = (e) => {
        e.preventDefault();

        items.forEach((other) => {
          if (other === item) return;
          const otherTl = timelines.get(other);
          if (otherTl && !otherTl.reversed()) otherTl.reverse();
        });

        if (tl.reversed()) tl.play(0);
        else tl.reverse();
      };

      trigger.addEventListener("click", onClick);
      listeners.push(() => trigger.removeEventListener("click", onClick));
    });

    const first = items[0];
    const firstTl = first ? timelines.get(first) : null;
    if (firstTl && firstTl.reversed()) firstTl.play(0);

    addCleanup(() => {
      listeners.forEach((off) => off());
      timelines.forEach((tl) => tl.kill());
    });
  }

  function initStars(scope) {
    qsa(scope, ".w-dyn-item").forEach((item) => {
      const ratingEl = item.querySelector(".rating-number");
      if (!ratingEl) return;

      const rating = Math.max(0, Math.min(5, parseInt(ratingEl.textContent, 10) || 0));
      qsa(item, ".review_star").forEach((star, i) => {
        star.style.display = i < rating ? "inline-block" : "none";
      });
    });
  }

  function isInViewport(el) {
    const rect = el.getBoundingClientRect();
    return rect.bottom > 0 && rect.top < window.innerHeight;
  }

  function initCenteredSliders(scope) {
  if (!window.gsap || !window.ScrollTrigger) return;

  const wrappers = qsa(scope, '[data-centered-slider="wrapper"]');
  if (!wrappers.length) return;

  wrappers.forEach((wrapper, wIndex) => {
    if (wrapper._sliderInitPending) return;
    wrapper._sliderInitPending = true;

    const startWhenReady = () => {
      const slides = qsa(wrapper, '[data-centered-slider="slide"]');
      if (!slides.length) {
        wrapper._sliderInitPending = false;
        return;
      }

      const boot = (attempt = 0) => {
        if (!wrapper.isConnected) {
          wrapper._sliderInitPending = false;
          return;
        }

        const freshSlides = qsa(wrapper, '[data-centered-slider="slide"]');
        if (!freshSlides.length) {
          wrapper._sliderInitPending = false;
          return;
        }

        if ((wrapper.offsetWidth === 0 || freshSlides[0].offsetWidth === 0) && attempt < 24) {
          requestAnimationFrame(() => boot(attempt + 1));
          return;
        }

        if (typeof wrapper._sliderDestroy === "function") {
          wrapper._sliderDestroy();
        }

        const slides = freshSlides;
        const bullets = qsa(wrapper, '[data-centered-slider="bullet"]');
        const prevButton = wrapper.querySelector('[data-centered-slider="prev-button"]');
        const nextButton = wrapper.querySelector('[data-centered-slider="next-button"]');

        let currentIndex = 0;
        let autoplayCall = null;
        const listeners = [];

        const autoplayEnabled = wrapper.getAttribute("data-slider-autoplay") === "true";
        const autoplayDuration = autoplayEnabled
          ? (parseFloat(wrapper.getAttribute("data-slider-autoplay-duration")) || 0)
          : 0;
        const canDrag = typeof window.Draggable === "function";

        gsap.set(slides, { clearProps: "x,xPercent,transform" });

        slides.forEach((slide, i) => slide.setAttribute("id", `slide-${wIndex}-${i}`));
        bullets.forEach((bullet, i) => {
          bullet.setAttribute("aria-controls", `slide-${wIndex}-${i}`);
          bullet.setAttribute("aria-selected", i === 0 ? "true" : "false");
        });

        const setActive = (index) => {
          slides.forEach((s, i) => s.classList.toggle("active", i === index));
          bullets.forEach((b, i) => {
            const active = i === index;
            b.classList.toggle("active", active);
            b.setAttribute("aria-selected", active ? "true" : "false");
          });
        };

        const loop = horizontalLoop(slides, {
          paused: true,
          draggable: canDrag,
          center: true,
          onChange: (_slide, index) => {
            currentIndex = index;
            setActive(index);
          }
        });

        if (!loop) {
          wrapper._sliderInitPending = false;
          return;
        }

        const startIndexAttr = parseInt(wrapper.getAttribute("data-slider-start-index") || "", 10);
        const startIndex = Number.isFinite(startIndexAttr)
          ? Math.max(0, Math.min(slides.length - 1, startIndexAttr))
          : Math.min(2, slides.length - 1);

        loop.toIndex(startIndex, { duration: 0.01 });
        currentIndex = startIndex;
        setActive(startIndex);

        const stopAutoplay = () => {
          if (!autoplayCall) return;
          autoplayCall.kill();
          autoplayCall = null;
        };

        const startAutoplay = () => {
          if (autoplayDuration <= 0 || autoplayCall) return;
          const tick = () => {
            loop.next({ ease: "osmo", duration: 0.725 });
            autoplayCall = gsap.delayedCall(autoplayDuration, tick);
          };
          autoplayCall = gsap.delayedCall(autoplayDuration, tick);
        };

        const visibilityTrigger = ScrollTrigger.create({
          trigger: wrapper,
          start: "top bottom",
          end: "bottom top",
          onEnter: startAutoplay,
          onLeave: stopAutoplay,
          onEnterBack: startAutoplay,
          onLeaveBack: stopAutoplay
        });

        const onMouseEnter = () => stopAutoplay();
        const onMouseLeave = () => {
          if (isInViewport(wrapper)) startAutoplay();
        };

        wrapper.addEventListener("mouseenter", onMouseEnter);
        wrapper.addEventListener("mouseleave", onMouseLeave);
        listeners.push(() => wrapper.removeEventListener("mouseenter", onMouseEnter));
        listeners.push(() => wrapper.removeEventListener("mouseleave", onMouseLeave));

        slides.forEach((slide, i) => {
          const onClick = (e) => {
            e.preventDefault?.();
            loop.toIndex(i, { ease: "osmo", duration: 0.725 });
          };
          slide.addEventListener("click", onClick);
          listeners.push(() => slide.removeEventListener("click", onClick));
        });

        bullets.forEach((bullet, i) => {
          const onClick = (e) => {
            e.preventDefault?.();
            loop.toIndex(i, { ease: "osmo", duration: 0.725 });
          };
          bullet.addEventListener("click", onClick);
          listeners.push(() => bullet.removeEventListener("click", onClick));
        });

        if (prevButton) {
          const onPrev = (e) => {
            e.preventDefault?.();
            loop.previous({ ease: "osmo", duration: 0.725 });
          };
          prevButton.addEventListener("click", onPrev);
          listeners.push(() => prevButton.removeEventListener("click", onPrev));
        }

        if (nextButton) {
          const onNext = (e) => {
            e.preventDefault?.();
            loop.next({ ease: "osmo", duration: 0.725 });
          };
          nextButton.addEventListener("click", onNext);
          listeners.push(() => nextButton.removeEventListener("click", onNext));
        }

        wrapper._sliderDestroy = () => {
          stopAutoplay();
          visibilityTrigger.kill(true);
          listeners.forEach((off) => off());
          loop._cleanupResize?.();
          loop.draggable?.kill?.();
          loop.kill?.();
          wrapper._sliderDestroy = null;
        };

        addCleanup(() => wrapper._sliderDestroy?.());

        wrapper._sliderInitPending = false;
        requestAnimationFrame(() => ScrollTrigger.refresh(true));
        setTimeout(() => ScrollTrigger.refresh(true), 120);
      };

      const imgs = qsa(wrapper, "img");
      if (!imgs.length) {
        boot();
        return;
      }

      let pending = 0;
      let started = false;
      const tryStart = () => {
        if (started) return;
        if (pending <= 0) {
          started = true;
          boot();
        }
      };

      imgs.forEach((img) => {
        if (img.complete) return;
        pending += 1;
        const done = () => {
          pending -= 1;
          tryStart();
        };
        img.addEventListener("load", done, { once: true });
        img.addEventListener("error", done, { once: true });
      });

      if (pending === 0) {
        boot();
      } else {
        setTimeout(() => {
          if (!started) {
            started = true;
            boot();
          }
        }, 700);
      }
    };

    startWhenReady();
  });
}



  function horizontalLoop(items, config = {}) {
    items = gsap.utils.toArray(items);
    if (!items.length) return null;

    const tl = gsap.timeline({
      repeat: config.repeat,
      paused: config.paused,
      defaults: { ease: "none" },
      onReverseComplete: () => tl.totalTime(tl.rawTime() + tl.duration() * 100)
    });

    const length = items.length;
    const startX = items[0].offsetLeft;
    const times = [];
    const widths = [];
    const spaceBefore = [];
    const xPercents = [];
    const pixelsPerSecond = (config.speed || 1) * 100;
    const snap = config.snap === false ? (v) => v : gsap.utils.snap(config.snap || 1);
    const center = config.center;
    const container = center === true
      ? items[0].parentNode
      : gsap.utils.toArray(center)[0] || items[0].parentNode;

    let totalWidth = 0;
    let timeWrap;
    let curIndex = 0;
    let lastIndex = 0;
    let indexIsDirty = false;
    let proxy;

    const getTotalWidth = () =>
      items[length - 1].offsetLeft +
      (xPercents[length - 1] / 100) * widths[length - 1] -
      startX +
      spaceBefore[0] +
      items[length - 1].offsetWidth * gsap.getProperty(items[length - 1], "scaleX") +
      (parseFloat(config.paddingRight) || 0);

    const populateWidths = () => {
      let b1 = container.getBoundingClientRect();
      let b2;

      items.forEach((item, i) => {
        widths[i] = parseFloat(gsap.getProperty(item, "width", "px"));
        xPercents[i] = snap(
          (parseFloat(gsap.getProperty(item, "x", "px")) / widths[i]) * 100 +
          gsap.getProperty(item, "xPercent")
        );

        b2 = item.getBoundingClientRect();
        spaceBefore[i] = b2.left - (i ? b1.right : b1.left);
        b1 = b2;
      });

      gsap.set(items, { xPercent: (i) => xPercents[i] });
      totalWidth = getTotalWidth();
    };

    const populateTimeline = () => {
      tl.clear();

      items.forEach((item, i) => {
        const curX = (xPercents[i] / 100) * widths[i];
        const distanceToStart = item.offsetLeft + curX - startX + spaceBefore[0];
        const distanceToLoop = distanceToStart + widths[i] * gsap.getProperty(item, "scaleX");

        tl.to(
          item,
          {
            xPercent: snap(((curX - distanceToLoop) / widths[i]) * 100),
            duration: distanceToLoop / pixelsPerSecond
          },
          0
        ).fromTo(
          item,
          { xPercent: snap(((curX - distanceToLoop + totalWidth) / widths[i]) * 100) },
          {
            xPercent: xPercents[i],
            duration: (curX - distanceToLoop + totalWidth - curX) / pixelsPerSecond,
            immediateRender: false
          },
          distanceToLoop / pixelsPerSecond
        ).add(`label${i}`, distanceToStart / pixelsPerSecond);

        times[i] = distanceToStart / pixelsPerSecond;
      });

      timeWrap = gsap.utils.wrap(0, tl.duration());
    };

    const populateOffsets = () => {
      if (!center) return;
      const offset = (tl.duration() * (container.offsetWidth / 2)) / totalWidth;
      times.forEach((time, i) => {
        times[i] = timeWrap(
          tl.labels[`label${i}`] + (tl.duration() * widths[i]) / 2 / totalWidth - offset
        );
      });
    };

    const getClosest = (values, value, wrap) => {
      let index = 0;
      let closest = 1e10;

      for (let i = values.length - 1; i >= 0; i -= 1) {
        let d = Math.abs(values[i] - value);
        if (d > wrap / 2) d = wrap - d;
        if (d < closest) {
          closest = d;
          index = i;
        }
      }

      return index;
    };

    const refresh = (deep) => {
      const progress = tl.progress();
      tl.progress(0, true);
      populateWidths();
      if (deep) populateTimeline();
      populateOffsets();
      if (deep && tl.draggable) tl.time(times[curIndex], true);
      else tl.progress(progress, true);
    };

    const onResize = () => refresh(true);

    gsap.set(items, { x: 0 });
    populateWidths();
    populateTimeline();
    populateOffsets();
    window.addEventListener("resize", onResize);

    const toIndex = (index, vars = {}) => {
      if (Math.abs(index - curIndex) > length / 2) {
        index += index > curIndex ? -length : length;
      }

      const newIndex = gsap.utils.wrap(0, length, index);
      let time = times[newIndex];

      if ((time > tl.time()) !== (index > curIndex) && index !== curIndex) {
        time += tl.duration() * (index > curIndex ? 1 : -1);
      }

      if (time < 0 || time > tl.duration()) {
        vars.modifiers = { time: timeWrap };
      }

      curIndex = newIndex;
      vars.overwrite = true;
      if (proxy) gsap.killTweensOf(proxy);

      return vars.duration === 0 ? tl.time(timeWrap(time)) : tl.tweenTo(time, vars);
    };

    tl.toIndex = (index, vars) => toIndex(index, vars);
    tl.closestIndex = (setCurrent) => {
      const index = getClosest(times, tl.time(), tl.duration());
      if (setCurrent) {
        curIndex = index;
        indexIsDirty = false;
      }
      return index;
    };
    tl.current = () => (indexIsDirty ? tl.closestIndex(true) : curIndex);
    tl.next = (vars) => toIndex(tl.current() + 1, vars);
    tl.previous = (vars) => toIndex(tl.current() - 1, vars);
    tl.times = times;

    tl.progress(1, true).progress(0, true);

    if (config.reversed) {
      tl.vars.onReverseComplete();
      tl.reverse();
    }

    if (config.onChange) {
      tl.eventCallback("onUpdate", () => {
        const i = tl.closestIndex();
        if (lastIndex !== i) {
          lastIndex = i;
          config.onChange(items[i], i);
        }
      });
    }

    if (config.draggable && typeof Draggable === "function") {
      proxy = document.createElement("div");
      const wrapProgress = gsap.utils.wrap(0, 1);
      let ratio;
      let startProgress;
      let draggable;
      let lastSnap;
      let initChangeX;
      let wasPlaying;

      const align = () => tl.progress(wrapProgress(startProgress + (draggable.startX - draggable.x) * ratio));
      const syncIndex = () => tl.closestIndex(true);

      draggable = Draggable.create(proxy, {
        trigger: items[0].parentNode,
        type: "x",
        lockAxis: true,
        allowNativeTouchScrolling: true,
        dragClickables: true,
        inertia: !!window.InertiaPlugin,
        overshootTolerance: 0,
        onPressInit() {
          const x = this.x;
          gsap.killTweensOf(tl);
          wasPlaying = !tl.paused();
          tl.pause();
          startProgress = tl.progress();
          refresh();
          ratio = 1 / totalWidth;
          initChangeX = startProgress / -ratio - x;
          gsap.set(proxy, { x: startProgress / -ratio });
        },
        onDrag: align,
        onThrowUpdate: align,
        snap(value) {
          if (Math.abs(startProgress / -ratio - this.x) < 10) return lastSnap + initChangeX;

          const time = -(value * ratio) * tl.duration();
          const wrappedTime = timeWrap(time);
          const snapTime = times[getClosest(times, wrappedTime, tl.duration())];
          let dif = snapTime - wrappedTime;

          if (Math.abs(dif) > tl.duration() / 2) {
            dif += dif < 0 ? tl.duration() : -tl.duration();
          }

          lastSnap = (time + dif) / tl.duration() / -ratio;
          return lastSnap;
        },
        onRelease() {
          syncIndex();
          if (draggable.isThrowing) indexIsDirty = true;
        },
        onThrowComplete() {
          syncIndex();
          if (wasPlaying) tl.play();
        }
      })[0];

      tl.draggable = draggable;
    }

    tl.closestIndex(true);
    lastIndex = curIndex;
    if (config.onChange) config.onChange(items[curIndex], curIndex);

    tl._cleanupResize = () => window.removeEventListener("resize", onResize);
    return tl;
  }

  function initBgVideo(scope) {
    if (!window.gsap || !window.ScrollTrigger) return;

    const targets = qsa(scope, ".bg_video_inner");
    if (!targets.length) return;

    const triggers = [];

    targets.forEach((el) => {
      gsap.killTweensOf(el);

      if (state.reducedMotion) {
        gsap.set(el, { scale: 1, clearProps: "transformOrigin" });
        return;
      }

      gsap.set(el, { scale: 0.85, transformOrigin: "50% 50%" });

      const st = ScrollTrigger.create({
        trigger: el,
        start: "top 75%",
        once: true,
        onEnter: () => {
          gsap.to(el, {
            scale: 1,
            duration: 0.9,
            ease: "power2.out",
            overwrite: "auto"
          });
        }
      });

      triggers.push(st);
    });

    addCleanup(() => {
      targets.forEach((el) => gsap.killTweensOf(el));
      triggers.forEach((st) => st.kill(true));
    });
  }

  function initProcessSteps(scope) {
    if (!window.gsap || !window.ScrollTrigger) return;

    const steps = qsa(scope, ".process_step_wrapper");
    if (!steps.length) return;

    const DURATION = 0.65;
    const EASE = "power2.inOut";
    const WRAP_SCALE = 1.06;
    const isDesktop = window.matchMedia("(min-width: 992px)").matches;
    const pos = isDesktop ? { start: "top 70%", end: "bottom 30%" } : { start: "top 85%", end: "bottom 15%" };

    const items = [];
    let active = null;

    steps.forEach((step) => {
      const inner = step.querySelector(".process_step_inner");
      const bg = step.querySelector(".process_step_bg");
      const numberWrap = step.querySelector(".step_nmbr_wrap");
      const imgWrap = step.querySelector(".process_img_wrap");
      if (!inner || !bg || !numberWrap) return;

      gsap.killTweensOf([bg, numberWrap, imgWrap].filter(Boolean));

      gsap.set(inner, { position: "relative", overflow: "hidden" });
      gsap.set(bg, { scaleY: 0, willChange: "transform", transformOrigin: "50% 0%" });
      if (imgWrap) gsap.set(imgWrap, { scale: 1, transformOrigin: "50% 50%", willChange: "transform" });

      if (!step.dataset.origNumberColor) {
        step.dataset.origNumberColor = getComputedStyle(numberWrap).color;
      }

      items.push({ step, bg, numberWrap, imgWrap, st: null });
    });

    const close = (item, direction) => {
      gsap.set(item.bg, { transformOrigin: direction === 1 ? "50% 100%" : "50% 0%" });
      gsap.to(item.bg, { scaleY: 0, duration: DURATION, ease: EASE, overwrite: "auto" });
      gsap.to(item.numberWrap, {
        color: item.step.dataset.origNumberColor || "",
        duration: DURATION,
        ease: EASE,
        overwrite: "auto"
      });
      if (item.imgWrap) gsap.to(item.imgWrap, { scale: 1, duration: DURATION, ease: EASE, overwrite: "auto" });
    };

    const open = (item, direction) => {
      if (active && active !== item) close(active, direction);
      active = item;

      gsap.set(item.bg, { transformOrigin: direction === 1 ? "50% 0%" : "50% 100%" });
      gsap.to(item.bg, { scaleY: 1, duration: DURATION, ease: EASE, overwrite: "auto" });
      gsap.to(item.numberWrap, { color: "#ffffff", duration: DURATION, ease: EASE, overwrite: "auto" });
      if (item.imgWrap) gsap.to(item.imgWrap, { scale: WRAP_SCALE, duration: DURATION, ease: EASE, overwrite: "auto" });
    };

    items.forEach((item) => {
      item.st = ScrollTrigger.create({
        trigger: item.step,
        start: pos.start,
        end: pos.end,
        invalidateOnRefresh: true,
        onToggle: (self) => {
          if (self.isActive) open(item, self.direction);
          else if (active === item) {
            close(item, self.direction);
            active = null;
          }
        }
      });
    });

    refreshScrollHard();

    addCleanup(() => {
      items.forEach((item) => {
        item.st?.kill(true);
        gsap.killTweensOf([item.bg, item.numberWrap, item.imgWrap].filter(Boolean));
      });
      active = null;
    });
  }

  function initScopedParallax(scope) {
    if (!window.gsap || !window.ScrollTrigger) return;

    const ctx = gsap.context(() => {
      const overlays = qsa(scope, ".overlay_content_wrap");
      const overlayTriggers = qsa(scope, ".big_img_inner");

      overlays.forEach((el, i) => {
        const trigger = overlayTriggers[i] || overlayTriggers[0];
        if (!trigger) return;

        gsap.fromTo(
          el,
          { y: "-7rem" },
          {
            y: "7rem",
            ease: "none",
            scrollTrigger: {
              trigger,
              start: "top bottom",
              end: "bottom top",
              scrub: true
            }
          }
        );
      });

      const absImgs = qsa(scope, ".abs_img_01");
      const absTriggers = qsa(scope, ".section_hero_centertext");

      absImgs.forEach((el, i) => {
        const trigger = absTriggers[i] || absTriggers[0];
        if (!trigger) return;

        gsap.fromTo(
          el,
          { y: "-5rem" },
          {
            y: "5rem",
            ease: "none",
            scrollTrigger: {
              trigger,
              start: "top bottom",
              end: "bottom top",
              scrub: true
            }
          }
        );
      });
    }, scope);

    addCleanup(() => ctx.revert());
  }

  function initPricingToggles(scope) {
    const sections = qsa(scope, "[data-pricing-section]");
    if (!sections.length) return;

    const localCleanups = [];

    sections.forEach((section) => {
      const toggle = section.querySelector(".pricing-toggle");
      const input = toggle?.querySelector(".pricing-toggle__checkbox");
      if (!toggle || !input) return;

      const cards = qsa(section, ".pricing_card");

      const apply = () => {
        const isGym = !!input.checked;
        cards.forEach((card) => {
          const gymEl = card.querySelector("[data-pricing-gym]");
          const noGymEl = card.querySelector("[data-pricing-nogym]");
          if (!gymEl || !noGymEl) return;
          gymEl.style.display = isGym ? "" : "none";
          noGymEl.style.display = isGym ? "none" : "";
        });
      };

      const onChange = () => apply();
      input.addEventListener("change", onChange);
      localCleanups.push(() => input.removeEventListener("change", onChange));

      apply();
    });

    addCleanup(() => localCleanups.forEach((fn) => fn()));
  }

  function initDraggableMarquee(scope) {
    if (!window.gsap || !window.ScrollTrigger || !window.Observer) return;

    const wrappers = qsa(scope, "[data-draggable-marquee-init]");
    if (!wrappers.length) return;

    const localCleanups = [];

    const getNumberAttr = (el, name, fallback) => {
      const value = parseFloat(el.getAttribute(name));
      return Number.isFinite(value) ? value : fallback;
    };

    wrappers.forEach((wrapper) => {
      const collection = wrapper.querySelector("[data-draggable-marquee-collection]");
      const list = wrapper.querySelector("[data-draggable-marquee-list]");
      if (!collection || !list) return;

      qsa(collection, "[data-draggable-marquee-clone]").forEach((clone) => clone.remove());

      const duration = getNumberAttr(wrapper, "data-duration", 20);
      const multiplier = getNumberAttr(wrapper, "data-multiplier", 40);
      const sensitivity = getNumberAttr(wrapper, "data-sensitivity", 0.01);

      const wrapperWidth = wrapper.getBoundingClientRect().width;
      const listWidth = list.scrollWidth || list.getBoundingClientRect().width;
      if (!wrapperWidth || !listWidth) return;

      const minRequiredWidth = wrapperWidth + listWidth + 2;
      while (collection.scrollWidth < minRequiredWidth) {
        const listClone = list.cloneNode(true);
        listClone.setAttribute("data-draggable-marquee-clone", "");
        listClone.setAttribute("aria-hidden", "true");
        collection.appendChild(listClone);
      }

      const wrapX = gsap.utils.wrap(-listWidth, 0);
      gsap.set(collection, { x: 0 });

      const marqueeLoop = gsap.to(collection, {
        x: -listWidth,
        duration,
        ease: "none",
        repeat: -1,
        onReverseComplete: () => marqueeLoop.progress(1),
        modifiers: {
          x: (x) => `${wrapX(parseFloat(x))}px`
        }
      });

      const initialDirection = (wrapper.getAttribute("data-direction") || "left").toLowerCase();
      const baseDirection = initialDirection === "right" ? -1 : 1;
      const timeScale = { value: baseDirection };

      const applyTimeScale = () => {
        marqueeLoop.timeScale(timeScale.value);
        wrapper.setAttribute("data-direction", timeScale.value < 0 ? "right" : "left");
      };

      if (baseDirection < 0) marqueeLoop.progress(1);
      applyTimeScale();

      const marqueeObserver = Observer.create({
        target: wrapper,
        type: "pointer,touch",
        preventDefault: true,
        debounce: false,
        onChangeX: (evt) => {
          let velocityTimeScale = evt.velocityX * -sensitivity;
          velocityTimeScale = gsap.utils.clamp(-multiplier, multiplier, velocityTimeScale);

          gsap.killTweensOf(timeScale);

          const restingDirection = velocityTimeScale < 0 ? -1 : 1;

          gsap.timeline({ onUpdate: applyTimeScale })
            .to(timeScale, { value: velocityTimeScale, duration: 0.1, overwrite: true })
            .to(timeScale, { value: restingDirection, duration: 1.0 });
        }
      });

      marqueeObserver.disable();

      const st = ScrollTrigger.create({
        trigger: wrapper,
        start: "top bottom",
        end: "bottom top",
        onEnter: () => { marqueeLoop.resume(); applyTimeScale(); marqueeObserver.enable(); },
        onEnterBack: () => { marqueeLoop.resume(); applyTimeScale(); marqueeObserver.enable(); },
        onLeave: () => { marqueeLoop.pause(); marqueeObserver.disable(); },
        onLeaveBack: () => { marqueeLoop.pause(); marqueeObserver.disable(); }
      });

      localCleanups.push(() => {
        st.kill(true);
        marqueeObserver.kill();
        marqueeLoop.kill();
        gsap.killTweensOf(timeScale);
        qsa(collection, "[data-draggable-marquee-clone]").forEach((clone) => clone.remove());
      });
    });

    addCleanup(() => localCleanups.forEach((fn) => fn()));
  }

  const DEFAULT_CAL_LOCALE = "nl-NL";

  function parseLocaleNumber(value) {
    if (typeof value !== "string" && typeof value !== "number") return NaN;
    return Number(String(value).trim().replace(",", "."));
  }

  function normalizeSex(value) {
    const v = String(value || "").trim().toLowerCase();
    if (v === "man" || v === "male" || v === "m") return "male";
    if (v === "vrouw" || v === "female" || v === "f") return "female";
    return "";
  }

  function formatKcal(value, locale) {
    return new Intl.NumberFormat(locale || DEFAULT_CAL_LOCALE, {
      maximumFractionDigits: 0
    }).format(Math.round(value));
  }

  function calculateBmr(sex, weightKg, heightCm, ageYears) {
    if (sex === "male") return 13.397 * weightKg + 4.799 * heightCm - 5.677 * ageYears + 88.362;
    if (sex === "female") return 9.247 * weightKg + 3.098 * heightCm - 4.33 * ageYears + 447.593;
    return NaN;
  }

  function initCalorieCalculators(scope) {
    const roots = qsa(scope, "[data-calorie-calculator]");
    if (!roots.length) return;

    const localCleanups = [];
    const setText = (el, text) => { if (el) el.textContent = text; };
    const show = (el) => { if (!el) return; el.hidden = false; el.style.display = ""; };
    const hide = (el) => { if (!el) return; el.hidden = true; };

    roots.forEach((root) => {
      const sexEls = qsa(root, "[data-calorie-sex]");
      const weightEl = root.querySelector("[data-calorie-weight]");
      const heightEl = root.querySelector("[data-calorie-height]");
      const ageEl = root.querySelector("[data-calorie-age]");
      const palEl = root.querySelector("[data-calorie-pal]");

      const buttonEl = root.querySelector("[data-calorie-calculate]");
      const outputEl = root.querySelector("[data-calorie-output]");
      const bmrOutputEl = root.querySelector("[data-calorie-bmr-output]");
      const errorEl = root.querySelector("[data-calorie-error]");
      const ctaEl = root.querySelector("[data-calorie-cta]");
      const ctaKcalEl = root.querySelector("[data-calorie-cta-kcal]");
      const ctaLinkEl = ctaEl ? ctaEl.querySelector("a[href]") : null;

      if (!sexEls.length || !weightEl || !heightEl || !ageEl || !palEl || !outputEl) return;

      const locale = root.getAttribute("data-calorie-locale") || DEFAULT_CAL_LOCALE;
      const autoCalculate = root.hasAttribute("data-calorie-auto");
      const formEl = root.matches("form") ? root : root.querySelector("form") || root.closest("form");

      if (ctaLinkEl) ctaLinkEl.classList.add("text_link");

      const listeners = [];
      const on = (el, type, handler) => {
        if (!el) return;
        el.addEventListener(type, handler);
        listeners.push(() => el.removeEventListener(type, handler));
      };

      const clearError = () => {
        setText(errorEl, "");
        hide(errorEl);
      };

      const setError = (message) => {
        setText(errorEl, message);
        show(errorEl);
      };

      const runCalculation = () => {
        clearError();

        let sex = "";
        if (sexEls.length === 1 && sexEls[0].type !== "radio") {
          sex = normalizeSex(sexEls[0].value);
        } else {
          sexEls.forEach((el) => {
            if (!sex && el.checked) sex = normalizeSex(el.value);
          });
        }

        const weight = parseLocaleNumber(weightEl.value);
        const height = parseLocaleNumber(heightEl.value);
        const age = parseLocaleNumber(ageEl.value);
        const pal = parseLocaleNumber(palEl.value);

        if (!sex) return setError("Kies een geldig geslacht.");
        if (!(weight > 0)) return setError("Vul een geldig gewicht in (kg).");
        if (!(height > 0)) return setError("Vul een geldige lengte in (cm).");
        if (!(age > 0)) return setError("Vul een geldige leeftijd in.");
        if (!(pal >= 1.2 && pal <= 2.4)) return setError("Kies een geldige PAL-waarde (1.2 t/m 2.4).");

        const bmr = calculateBmr(sex, weight, height, age);
        const total = bmr * pal;

        setText(outputEl, formatKcal(total, locale));
        if (bmrOutputEl) setText(bmrOutputEl, formatKcal(bmr, locale));

        if (ctaKcalEl) setText(ctaKcalEl, formatKcal(total, locale));
        show(ctaEl);
      };

      on(buttonEl, "click", (event) => {
        event.preventDefault();
        runCalculation();
      });

      const onSubmit = (event) => {
        event.preventDefault();
        event.stopPropagation();
        runCalculation();
      };

      if (formEl) on(formEl, "submit", onSubmit);
      else on(root, "submit", onSubmit);

      if (autoCalculate) {
        sexEls.forEach((el) => {
          on(el, "input", runCalculation);
          on(el, "change", runCalculation);
        });

        [weightEl, heightEl, ageEl, palEl].forEach((el) => {
          on(el, "input", runCalculation);
          on(el, "change", runCalculation);
        });
      }

      localCleanups.push(() => listeners.forEach((off) => off()));
    });

    addCleanup(() => localCleanups.forEach((fn) => fn()));
  }

  function initDobYearSelects(scope) {
    const yearSelects = qsa(scope, "[data-dob-year]");
    if (!yearSelects.length) return;

    const currentYear = new Date().getFullYear();
    const minYear = 1900;

    yearSelects.forEach((select) => {
      if (select.dataset.dobYearsReady === "true") return;

      for (let y = currentYear; y >= minYear; y -= 1) {
        const option = document.createElement("option");
        option.value = String(y);
        option.textContent = String(y);
        select.appendChild(option);
      }

      select.dataset.dobYearsReady = "true";
    });
  }

  function initMultiStepForms(scope) {
    const forms = qsa(scope, "[data-multistep-form]");
    if (!forms.length) return;

    const localCleanups = [];

    const isVisible = (el) => !!(el && (el.offsetWidth || el.offsetHeight || el.getClientRects().length));

    const validateStep = (stepEl) => {
      const fields = qsa(stepEl, "input, select, textarea")
        .filter((el) => !el.disabled && (isVisible(el) || el.type === "hidden"));

      for (const field of fields) {
        if (!field.checkValidity()) {
          field.reportValidity();
          try { field.focus(); } catch (_) {}
          return false;
        }
      }

      return true;
    };

    forms.forEach((form) => {
      const steps = qsa(form, "[data-step]").sort(
        (a, b) => Number(a.getAttribute("data-step")) - Number(b.getAttribute("data-step"))
      );
      if (!steps.length) return;

      const indicator = form.querySelector("[data-step-indicator]") || document.querySelector("[data-step-indicator]");
      const elCurrent = indicator ? indicator.querySelector("[data-step-current]") : null;
      const elTotal = indicator ? indicator.querySelector("[data-step-total]") : null;
      const elBar = indicator ? indicator.querySelector("[data-step-progress]") : null;

      const total = steps.length;
      if (elTotal) elTotal.textContent = String(total);

      let currentIndex = 0;

      const updateIndicator = () => {
        const stepNum = Number(steps[currentIndex].getAttribute("data-step")) || (currentIndex + 1);
        if (elCurrent) elCurrent.textContent = String(stepNum);

        if (elBar) {
          const pct = total <= 1 ? 100 : (currentIndex / (total - 1)) * 100;
          elBar.style.width = `${Math.max(0, Math.min(100, pct))}%`;
        }

        form.setAttribute("data-step-active", String(stepNum));
      };

      const showStep = (index) => {
        currentIndex = Math.max(0, Math.min(total - 1, index));
        steps.forEach((step, i) => step.setAttribute("data-step-active", i === currentIndex ? "true" : "false"));
        updateIndicator();
      };

      const onClick = (e) => {
        const next = e.target.closest("[data-step-next]");
        const prev = e.target.closest("[data-step-prev]");
        const submitFake = e.target.closest("[data-step-submit]");
        if (!next && !prev && !submitFake) return;

        e.preventDefault();

        if (next) {
          if (!validateStep(steps[currentIndex])) return;
          showStep(currentIndex + 1);
          return;
        }

        if (prev) {
          showStep(currentIndex - 1);
          return;
        }

        if (!validateStep(steps[currentIndex])) return;
        const real = form.querySelector(".real-submit[type='submit'], button.real-submit[type='submit']");
        if (real) real.click();
        else form.requestSubmit?.();
      };

      const onSubmit = (e) => {
        if (currentIndex === total - 1) return;
        e.preventDefault();
        if (!validateStep(steps[currentIndex])) return;
        showStep(total - 1);
      };

      form.addEventListener("click", onClick);
      form.addEventListener("submit", onSubmit);
      showStep(0);

      localCleanups.push(() => {
        form.removeEventListener("click", onClick);
        form.removeEventListener("submit", onSubmit);
      });
    });

    addCleanup(() => localCleanups.forEach((fn) => fn()));
  }

  function initPage(scope) {
    runCleanups();

    initHeadingVisibility(scope);

    initWipes(scope);
    initImageStair(scope);
    initHighlightText(scope);
    initHeadingSplit(scope);
    initCenteredSliders(scope);
    initFAQ(scope);
    initStars(scope);

    initBgVideo(scope);
    initProcessSteps(scope);
    initScopedParallax(scope);
    initPricingToggles(scope);
    initDraggableMarquee(scope);
    initCalorieCalculators(scope);
    initDobYearSelects(scope);
    initMultiStepForms(scope);

    refreshScrollHard();
  }

  function initOnce() {
    registerPlugins();
    initLenis();

    if (state.onceReady) return;
    state.onceReady = true;

    if (!state.resizeHandler) {
      state.resizeHandler = () => refreshScrollHard();
      window.addEventListener("resize", state.resizeHandler);
    }

    if (document.readyState === "complete") {
      document.body.classList.add("page-loaded");
    } else {
      window.addEventListener("load", () => document.body.classList.add("page-loaded"), { once: true });
    }
  }

  function initBarba() {
    if (!window.barba || !window.gsap) return;

    barba.hooks.beforeEnter((data) => {
      gsap.set(data.next.container, {
        position: "fixed",
        top: 0,
        left: 0,
        right: 0
      });

      stopLenis();
      applyThemeFrom(data.next.container);
    });

    barba.hooks.beforeLeave(() => {
      runCleanups();
    });

    barba.hooks.afterLeave(() => {
      runCleanups();
    });

    barba.hooks.enter((data) => {
      initBarbaNavUpdate(data);
    });

    barba.hooks.afterEnter((data) => {
      reinitWebflow(data);
      initPage(data.next.container);
      startLenis();
      refreshScrollHard();
    });

    barba.init({
      debug: false,
      timeout: 7000,
      preventRunning: true,
      transitions: [
        {
          name: "default",
          sync: true,
          once(data) {
            initOnce();
            applyThemeFrom(data.next.container);
            initPage(data.next.container);
            return runPageOnceAnimation(data.next.container);
          },
          leave(data) {
            return runPageLeaveAnimation(data.current.container);
          },
          enter(data) {
            return runPageEnterAnimation(data.next.container);
          }
        }
      ]
    });
  }

function reinitWebflow(data) {
  if (!window.Webflow) return;

  try {
    // Update Webflow page ID from the incoming page HTML
    if (data?.next?.html) {
      const parser = new DOMParser();
      const dom = parser.parseFromString(data.next.html, "text/html");
      const wfPage = dom.documentElement.getAttribute("data-wf-page");

      if (wfPage) {
        document.documentElement.setAttribute("data-wf-page", wfPage);
      }
    }

    // Reboot Webflow on the swapped page
    window.Webflow.destroy();
    window.Webflow.ready();

    // Re-init interactions/forms if available
    window.Webflow.require?.("ix2")?.init();
    window.Webflow.require?.("forms")?.init();
  } catch (err) {
    console.error("Webflow reinit failed:", err);
  }
}
  
  function boot(tries = 0) {
    if (!window.gsap) {
      if (tries < 200) setTimeout(() => boot(tries + 1), 50);
      return;
    }

    if (!window.barba) {
      if (tries < 200) {
        setTimeout(() => boot(tries + 1), 50);
        return;
      }

      initOnce();
      initPage(document);
      return;
    }

    initOnce();
    initBarba();
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", () => boot());
  } else {
    boot();
  }

  window.__BARBA_GSAP_SCOPED__ = {
    destroy() {
      runCleanups();
      stopLenis();

      try { state.lenis?.destroy?.(); } catch (_) {}
      state.lenis = null;

      if (state.resizeHandler) {
        window.removeEventListener("resize", state.resizeHandler);
        state.resizeHandler = null;
      }

      state.rmMQ.removeEventListener?.("change", onReducedMotionChange);
      state.rmMQ.removeListener?.(onReducedMotionChange);
    }
  };
})();
